s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

def lambda_handler(event, context):
    function_name = os.environ.get('AWS_LAMBDA_FUNCTION_NAME', 'unknown')
    
    try:
        table_name = os.environ.get('DYNAMODB_TABLE', 'microservices-data')
        table = dynamodb.Table(table_name)
        
        request_id = context.request_id
        timestamp = datetime.utcnow().isoformat()
        
        item = {
            'id': request_id,
            'function_name': function_name,
            'timestamp': timestamp,
            'event': json.dumps(event)
        }
        
        table.put_item(Item=item)
        
        bucket_name = os.environ.get('S3_BUCKET', 'microservices-logs')
        s3_key = f'logs/{function_name}/{timestamp}.json'
        
        s3_client.put_object(
            Bucket=bucket_name,
            Key=s3_key,
            Body=json.dumps(item),
            ContentType='application/json'
        )
        
        topic_arn = os.environ.get('SNS_TOPIC_ARN')
        if topic_arn:
            sns_client.publish(
                TopicArn=topic_arn,
                Subject=f'Lambda Execution: {function_name}',
                Message=json.dumps({
                    'function': function_name,
                    'request_id': request_id,
                    'timestamp': timestamp,
                    'status': 'success'
                })
            )
        
        queue_url = os.environ.get('SQS_QUEUE_URL')
        if queue_url:
            sqs_client.send_message(
                QueueUrl=queue_url,
                MessageBody=json.dumps({
                    'function': function_name,
                    'request_id': request_id,
                    'timestamp': timestamp,
                    'event': event
                })
            )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Success',
                'function': function_name,
                'request_id': request_id,
                'timestamp': timestamp
            })
        }
        
    except Exception as e:
        error_message = str(e)
        print(f'Error in {function_name}: {error_message}')
        
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Error',
                'error': error_message,
                'function': function_name
            })
        }